#include <stdio.h>
#include <stdlib.h>

float bayes_classification(float* prior_probabilities, float* likelihoods, int data[], int n) {
 float posterior_probabilities[n];
 for (int i = 0; i < n; i++) {
 posterior_probabilities[i] = likelihoods[i] * prior_probabilities[i] / (likelihoods[i] * prior_probabilities[i]);
 }
 float max_posterior_probability = posterior_probabilities[0];
 int classified_class = 0;
 for (int i = 1; i < n; i++) {
 if (posterior_probabilities[i] > max_posterior_probability) {
 max_posterior_probability = posterior_probabilities[i];
 classified_class = i;
 }
 }
 return classified_class;
}

int main() {
 float prior_probabilities[] = {0.7, 0.3};
 float likelihoods[] = {0.8, 0.2};
 int data[] = {1, 2, 3};
 int n = sizeof(data) / sizeof(data[0]);
 int classified_class = bayes_classification(prior_probabilities, likelihoods, data, n);
 printf("Classified as class %d\n", classified_class);
 return 0;
}
